const CheckoutSteps = ({ active }) => {
  const steps = ['Prijava', 'Podaci o razmeni', 'Pregled zahteva'];

  return (
    <ol className="checkout-steps">
      {steps.map((step, index) => (
        <li className={index <= active ? 'enabled' : ''} key={step}>
          {step}
        </li>
      ))}
    </ol>
  );
};

export default CheckoutSteps;
